#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2025/4/7# @Author : cyq# @File : tasks# @Software: PyCharm# @Desc:from croe.interface.task import TaskRunnerfrom enums import StarterEnumfrom croe.interface.starter import APIStarterfrom croe.play.task_runner import PlayTaskRunnerfrom croe.play.starter import UIStarterfrom app.scheduler.celer7.app import celery_appimport asynciofrom celery.app.task import Taskfrom utils import log@celery_app.task(name="execute_api_task", bind=True)  # 👈 这个bind=True让函数接收self参数def execute_api_task(self: Task, task_id: int):    """    执行API任务    :param self Task    :param task_id:    :return:    """    async def _execute():        log.info(f"CELERY 执行任务: {task_id}")        return await TaskRunner(APIStarter(StarterEnum.Celery)).execute_task(task_id)    try:        self.update_state(state="PROGRESS", meta={"status": "任务开始"})        asyncio.run(_execute(), )        self.update_state(state="SUCCESS", meta={"status": "任务结束"})    except Exception as e:        log.error(f"API任务执行失败: {task_id}, 错误: {e}")        self.update_state(            state='FAILURE',            meta={'error': str(e)}        )        raise@celery_app.task(name="execute_ui_task", bind=True)def execute_ui_task(self: Task, task_id: int):    """    执行UI任务    :param self Task    :param task_id:    :return:    """    async def _execute():        return await PlayTaskRunner(UIStarter(StarterEnum.Celery)).execute_task(task_id)    try:        self.update_state(state="PROGRESS", meta={"status": "任务开始"})        asyncio.run(_execute())        self.update_state(state="SUCCESS", meta={"status": "任务结束"})    except Exception as e:        log.error(f"UI任务执行失败: {task_id}, 错误: {e}")        self.update_state(            state='FAILURE',            meta={'error': str(e)}        )        raise